const App: React.FC = () => {
  const [messages, setMessages] = useState<Message[]>([]);
  const [inputValue, setInputValue] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [isTTSActive, setIsTTSActive] = useState(false);
  const [isListening, setIsListening] = useState(false);
  const [currentVoice, setCurrentVoice] = useState('Kore'); // Default Voice
  const [isSettingsOpen, setIsSettingsOpen] = useState(false);
  const [toast, setToast] = useState<{message: string, type: 'error'|'info'} | null>(null);

  // Initialize sidebar to TRUE for tablet view
  const [isSidebarOpen, setIsSidebarOpen] = useState(true);

  const messagesEndRef = useRef<HTMLDivElement>(null);
  const inputRef = useRef<HTMLInputElement>(null);
  const recognitionRef = useRef<any>(null);

  // Ref to ensure TTS chunks are enqueued in order even if generated in parallel
  const ttsChainRef = useRef<Promise<void>>(Promise.resolve());

  // Initialize Chat on Mount
  useEffect(() => {
    initializeChat();
    // Add initial greeting
    setMessages([{
      id: 'init-1',
      role: 'model',
      text: '안녕하세요! 무엇을 도와드릴까요? 궁금한 정보를 물어보거나 편하게 대화해 보세요.',
      timestamp: new Date()
    }]);

    // Cleanup on unmount
    return () => {
      if (recognitionRef.current) {
        try {
            recognitionRef.current.stop();
        } catch(e) { /* ignore */ }
      }
      stopAudio(); // Cleanup audio on unmount
    };
  }, []);

  // Auto-scroll to bottom
  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages, isLoading]);

  const showToast = (message: string, type: 'error'|'info' = 'info') => {
    setToast({ message, type });
    setTimeout(() => setToast(null), 3000);
  };

  const handleSpeak = (text: string) => {
    if (!isTTSActive) return;

    // 1. Start Generation Immediately (Parallel)
    // We don't await here so multiple sentences can generate at once
    const generationPromise = generateSpeech(text, currentVoice)
      .catch((error: any) => {
        console.error("Failed to generate speech chunk:", error);
        showToast(error.message || "음성 생성 오류", "error");
        return null;
      });

    // 2. Queue the Enqueueing (Sequential)
    // This ensures audio playback happens in the correct order (Sentence 1 -> Sentence 2)
    // even if Sentence 2 finishes generating before Sentence 1.
    ttsChainRef.current = ttsChainRef.current.then(async () => {
      const audioData = await generationPromise;
      if (audioData) {
        enqueueAudio(audioData, text);
      }
    });
  };

  const handleToggleTTS = () => {
    const newState = !isTTSActive;
    setIsTTSActive(newState);
    if (!newState) {
      stopAudio();
      clearAudioQueue();
      showToast("음성 읽기가 꺼졌습니다.", "info");
    } else {
      showToast("음성 읽기가 켜졌습니다.", "info");
    }
  };

  const handleNewChat = () => {
    stopAudio();
    clearAudioQueue();
    setMessages([{
      id: Date.now().toString(),
      role: 'model',
      text: '안녕하세요! 새로운 대화를 시작합니다. 무엇을 도와드릴까요?',
      timestamp: new Date()
    }]);
    initializeChat();
    setInputValue('');
  };

  const startListening = () => {
    if (!('webkitSpeechRecognition' in window) && !('SpeechRecognition' in window)) {
      alert("이 브라우저는 음성 인식을 지원하지 않습니다.");
      return;
    }

    const SpeechRecognition = (window as any).SpeechRecognition || (window as any).webkitSpeechRecognition;

    // Cleanup previous instance if exists
    if (recognitionRef.current) {
        recognitionRef.current.onend = null; // Prevent triggering onend
        try {
            recognitionRef.current.stop();
        } catch (e) { /* ignore */ }
    }

    const recognition = new SpeechRecognition();
    recognition.lang = 'ko-KR';
    recognition.continuous = false;
    recognition.interimResults = false;

    recognition.onstart = () => {
      setIsListening(true);
      stopAudio(); // Stop TTS if user starts speaking
      clearAudioQueue();
    };

    recognition.onend = () => {
      setIsListening(false);
    };

    recognition.onresult = (event: any) => {
      const transcript = event.results[0][0].transcript;
      setInputValue(prev => {
        const trimmed = prev.trim();
        return trimmed ? `${trimmed} ${transcript}` : transcript;
      });
    };

    recognition.onerror = (event: any) => {
      console.error("Speech recognition error", event.error);
      setIsListening(false);
      if (event.error === 'not-allowed') {
        showToast("마이크 권한이 차단되었습니다.", "error");
      } else if (event.error === 'service-not-allowed') {
        showToast("음성 인식 서비스를 사용할 수 없습니다.", "error");
      } else {
        showToast("음성 인식 오류가 발생했습니다.", "error");
      }
    };

    recognitionRef.current = recognition;

    try {
        recognition.start();
    } catch (e) {
        console.error("Failed to start recognition:", e);
        setIsListening(false);
    }
  };

  const stopListening = () => {
    if (recognitionRef.current) {
      try {
        recognitionRef.current.stop();
      } catch (e) {
        console.warn("Could not stop recognition:", e);
      }
    }
  };

  const handleVoiceToggle = () => {
    if (isListening) {
      stopListening();
    } else {
      startListening();
    }
  };

  const handleSendMessage = async () => {
    if (!inputValue.trim() || isLoading) return;

    // Stop any existing audio when sending a new message
    stopAudio();
    clearAudioQueue();
    // Reset TTS Chain
    ttsChainRef.current = Promise.resolve();

    const userText = inputValue.trim();
    setInputValue('');

    // User Message
    const userMsg: Message = {
      id: Date.now().toString(),
      role: 'user',
      text: userText,
      timestamp: new Date()
    };

    setMessages(prev => [...prev, userMsg]);
    setIsLoading(true);

    // Placeholder for AI Message
    const aiMsgId = (Date.now() + 1).toString();
    const aiMsgPlaceholder: Message = {
      id: aiMsgId,
      role: 'model',
      text: '', // Start empty
      timestamp: new Date(),
      isStreaming: true
    };

    setMessages(prev => [...prev, aiMsgPlaceholder]);

    try {
      let fullText = "";
      let ttsBuffer = ""; 

      await sendMessageStream(userText, (chunkText, sources) => {
        // 1. Calculate new part of the text for TTS processing
        const newPart = chunkText.slice(fullText.length);
        fullText = chunkText;
        ttsBuffer += newPart;

        // 2. Immediate UI Update: Show text as soon as it arrives
        setMessages(prev => prev.map(msg => {
          if (msg.id === aiMsgId) {
            return {
              ...msg,
              text: fullText, 
              sources: sources || msg.sources
            };
          }
          return msg;
        }));

        // 3. TTS Processing: Detect sentences and queue them
        if (isTTSActive) {
            const sentenceEndRegex = /([.?!])\s+/g;
            let match;
            let lastIndex = 0;

            while ((match = sentenceEndRegex.exec(ttsBuffer)) !== null) {
                const sentence = ttsBuffer.substring(lastIndex, match.index + 1);
                handleSpeak(sentence); 
                lastIndex = match.index + match[0].length; 
            }

            if (lastIndex > 0) {
                ttsBuffer = ttsBuffer.substring(lastIndex);
            }
        }
      });

      // Post-stream cleanup
      setMessages(prev => prev.map(msg => {
        if (msg.id === aiMsgId) {
           return { ...msg, isStreaming: false };
        }
        return msg;
      }));

      // Handle remaining buffer (incomplete sentence at end)
      if (isTTSActive && ttsBuffer.trim()) {
        handleSpeak(ttsBuffer);
      }

    } catch (error) {
      setMessages(prev => prev.map(msg => {
        if (msg.id === aiMsgId) {
          return { ...msg, text: "죄송합니다. 오류가 발생했습니다.", isStreaming: false };
        }
        return msg;
      }));
      showToast("답변 생성 중 오류가 발생했습니다.", "error");
    } finally {
      setIsLoading(false);
      setTimeout(() => inputRef.current?.focus(), 100);
    }
  };

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      handleSendMessage();
    }
  };

  return (
    // Tablet Layout: Flex Row to allow sidebar to sit next to content
    <div className="flex flex-row h-[100dvh] w-full bg-[#121212] text-gray-100 font-sans overflow-hidden">

      {/* Toast Notification */}
      {toast && (
        <div className={`fixed top-4 left-1/2 transform -translate-x-1/2 z-50 flex items-center gap-2 px-4 py-3 rounded-lg shadow-lg animate-in slide-in-from-top-2 duration-200 ${
          toast.type === 'error' ? 'bg-red-500/90 text-white' : 'bg-emerald-600/90 text-white'
        }`}>
          {toast.type === 'error' && <AlertCircle size={18} />}
          <span className="text-sm font-medium">{toast.message}</span>
        </div>
      )}

      <SettingsModal 
        isOpen={isSettingsOpen}
        onClose={() => setIsSettingsOpen(false)}
        selectedVoice={currentVoice}
        onVoiceChange={setCurrentVoice}
      />

      <Sidebar 
        isOpen={isSidebarOpen} 
        onClose={() => setIsSidebarOpen(false)}
        onNewChat={handleNewChat}
        onOpenSettings={() => setIsSettingsOpen(true)}
      />

      {/* Main Content Area */}
      <div className="flex-1 flex flex-col h-full relative transition-all duration-300">

        {/* App Header */}
        <header className="flex items-center justify-between px-6 py-4 bg-[#1e1e1e] border-b border-gray-800 z-10 shrink-0">
          <div className="flex items-center gap-4">
            <button 
              onClick={() => setIsSidebarOpen(!isSidebarOpen)}
              className="p-2 -ml-2 text-gray-400 hover:text-white rounded-full hover:bg-gray-800 transition-colors"
            >
              <Menu size={24} />
            </button>
            <div className="bg-gradient-to-br from-emerald-500 to-blue-600 p-2 rounded-xl">
              <Sparkles size={20} className="text-white" />
            </div>
            <div>
              <h1 className="text-xl font-bold text-gray-100 leading-tight">MAZI AI Companion</h1>
              <p className="text-[11px] text-emerald-400 font-medium tracking-wide">ONLINE • GEMINI 2.5</p>
            </div>
          </div>
          <div className="flex items-center gap-2">
            <button 
              onClick={handleToggleTTS}
              className={`p-2 rounded-full transition-colors ${isTTSActive ? 'bg-emerald-500/20 text-emerald-400' : 'text-gray-500 hover:bg-gray-800'}`}
              title="음성 읽기 (TTS)"
            >
              {isTTSActive ? <Volume2 size={22} /> : <VolumeX size={22} />}
            </button>
            <button 
                onClick={() => setIsSettingsOpen(true)}
                className="p-2 text-gray-400 hover:text-white hover:bg-gray-800 rounded-full transition-colors"
            >
              <MoreVertical size={22} />
            </button>
          </div>
        </header>

        {/* Chat Area - Centered with max-width for Tablet readability */}
        <main className="flex-1 overflow-y-auto p-4 md:p-6 no-scrollbar scroll-smooth">
          <div className="max-w-4xl mx-auto w-full space-y-4">
            {messages.map((msg) => (
              <MessageBubble key={msg.id} message={msg} />
            ))}
            {/* Show typing indicator only when loading AND (not TTS active OR no text shown yet) */}
            {isLoading && messages[messages.length - 1]?.role === 'model' && messages[messages.length - 1]?.text === '' && (
              <TypingIndicator />
            )}
            <div ref={messagesEndRef} />
          </div>
        </main>

        {/* Input Area - Centered with max-width */}
        <footer className="p-4 md:p-6 bg-[#1e1e1e] border-t border-gray-800 z-0 shrink-0">
          <div className="max-w-4xl mx-auto w-full">
            <div className="flex items-end gap-3 bg-[#2a2a2a] p-2 rounded-[2rem] border border-gray-700 focus-within:border-emerald-500 transition-colors shadow-lg">
              <button className="p-3 text-gray-400 hover:text-emerald-400 transition-colors rounded-full hover:bg-[#333]">
                <Plus size={22} />
              </button>

              <input
                ref={inputRef}
                type="text"
                className="flex-1 bg-transparent border-none outline-none text-gray-100 placeholder-gray-500 py-3 text-base max-h-32 overflow-y-auto resize-none"
                placeholder="메시지를 입력하세요..."
                value={inputValue}
                onChange={(e) => setInputValue(e.target.value)}
                onKeyDown={handleKeyDown}
                autoComplete="off"
              />

              {/* Voice Input Button */}
              <button 
                onClick={handleVoiceToggle}
                className={`p-3 rounded-full transition-all ${
                    isListening 
                    ? 'bg-red-500/20 text-red-500 hover:bg-red-500/30 animate-pulse' 
                    : 'text-gray-400 hover:text-white hover:bg-[#333]'
                }`}
                title="음성 입력"
              >
                {isListening ? <MicOff size={22} /> : <Mic size={22} />}
              </button>

              {/* Send Button */}
              {inputValue.trim() && (
                <button
                  onClick={handleSendMessage}
                  disabled={isLoading}
                  className="p-3 bg-emerald-600 text-white rounded-full shadow-lg hover:bg-emerald-500 active:scale-95 transition-all disabled:opacity-50 disabled:scale-100"
                >
                  <Send size={20} fill="currentColor" />
                </button>
              )}
            </div>
            <div className="text-center mt-3">
              <p className="text-[11px] text-gray-600">AI는 실수를 할 수 있습니다. 중요한 정보를 확인하세요.</p>
            </div>
          </div>
        </footer>
      </div>
    </div>
  );
};

export default App;
