import { GoogleGenAI, Chat, Modality } from "@google/genai";
import { Source } from "../types";

let ai: GoogleGenAI | null = null;
let chatSession: Chat | null = null;

const MODEL_NAME = 'gemini-2.5-flash';
const TTS_MODEL_NAME = 'gemini-2.5-flash-preview-tts';

const SYSTEM_INSTRUCTION = `
당신은 도움이 되고 친절한 AI 비서입니다. 
한국어로 자연스럽게 대화하세요.
사용자의 질문에 대해 명확하고 정확한 정보를 제공하세요.
정보가 필요하면 Google 검색 도구를 적극적으로 활용하세요.
답변은 읽기 쉽게 서식을 갖추어 작성하세요.
`;

// Helper to initialize AI client lazily and safely
const getAIClient = (): GoogleGenAI => {
  if (!ai) {
    let apiKey = '';

    // 1. Try safe process.env access (Node/Webpack/Vercel standard)
    try {
      // @ts-ignore
      const proc = typeof process !== 'undefined' ? process : (window as any).process;
      if (proc && proc.env && proc.env.API_KEY) {
        apiKey = proc.env.API_KEY;
      }
    } catch (e) {
      console.warn("Failed to access process.env:", e);
    }

    // 2. Fallback for Vite (import.meta.env) if process didn't work
    if (!apiKey) {
      try {
        // @ts-ignore
        if (typeof import.meta !== 'undefined' && import.meta.env) {
           // @ts-ignore
           apiKey = import.meta.env.VITE_API_KEY || import.meta.env.API_KEY || '';
        }
      } catch (e) { /* ignore */ }
    }

    if (!apiKey) {
      console.warn("CRITICAL: Gemini API Key is missing. Please check Vercel Environment Variables.");
      // Do not throw here to avoid black screen. Just log.
      // The actual API call will fail later with a visible error toast.
    }

    ai = new GoogleGenAI({ apiKey: apiKey || 'MISSING_KEY_PLACEHOLDER' });
  }
  return ai;
};

export const initializeChat = () => {
  try {
    const client = getAIClient();
    chatSession = client.chats.create({
      model: MODEL_NAME,
      config: {
        systemInstruction: SYSTEM_INSTRUCTION,
        tools: [{ googleSearch: {} }],
      },
    });
  } catch (error) {
    console.error("Failed to initialize chat session:", error);
  }
};

export const sendMessageStream = async (
  message: string,
  onChunk: (text: string, sources?: Source[]) => void
): Promise<void> => {
  if (!chatSession) {
    initializeChat();
  }

  if (!chatSession) {
    throw new Error("채팅 세션을 초기화할 수 없습니다. API 키를 확인해 주세요.");
  }

  try {
    const resultStream = await chatSession.sendMessageStream({
      message: message,
    });

    let accumulatedText = "";

    for await (const chunk of resultStream) {
      const text = chunk.text || "";
      accumulatedText += text;

      let sources: Source[] | undefined = undefined;
      const groundingChunks = chunk.candidates?.[0]?.groundingMetadata?.groundingChunks;

      if (groundingChunks) {
        sources = groundingChunks
          .map((c: any) => c.web)
          .filter((w: any) => w && w.uri)
          .map((w: any) => ({
            title: w.title || "출처",
            uri: w.uri
          }));
      }

      onChunk(accumulatedText, sources);
    }
  } catch (error) {
    console.error("Error sending message:", error);
    throw error;
  }
};

export const generateSpeech = async (text: string, voiceName: string = "Kore"): Promise<string> => {
  try {
    const client = getAIClient();
    const response = await client.models.generateContent({
      model: TTS_MODEL_NAME,
      contents: [{ parts: [{ text: text }] }],
      config: {
        responseModalities: [Modality.AUDIO],
        speechConfig: {
          voiceConfig: {
            prebuiltVoiceConfig: { voiceName: voiceName },
          },
        },
      },
    });

    // Check if the model returned text instead of audio (e.g. refusal or error message)
    // Use response.text to correctly extract text output
    const textPart = response.text;
    if (textPart) {
        console.warn("TTS Model returned text instead of audio:", textPart);
        throw new Error(`음성 생성 거부: 모델이 텍스트를 반환했습니다. (${textPart})`);
    }

    // Extract base64 audio string
    const audioData = response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
    if (!audioData) {
      console.error("Full response for debugging:", JSON.stringify(response, null, 2));
      throw new Error("오디오 데이터가 수신되지 않았습니다. API 응답을 확인하세요.");
    }
    return audioData;
  } catch (error: any) {
    console.error("TTS generation error:", error);

    let userMessage = "음성 생성 중 오류가 발생했습니다.";

    // Map specific errors to user-friendly messages
    if (error.message) {
        if (error.message.includes("API key")) {
            userMessage = "API 키 오류: 키가 유효하지 않습니다.";
        } else if (error.message.includes("429") || error.message.includes("quota")) {
            userMessage = "요청 한도 초과: 잠시 후 다시 시도해주세요.";
        } else if (error.message.includes("503") || error.message.includes("500")) {
            userMessage = "서버 일시적 오류: 잠시 후 다시 시도해주세요.";
        } else if (error.message.includes("fetch failed") || error.message.includes("network")) {
            userMessage = "네트워크 오류: 인터넷 연결을 확인해주세요.";
        } else if (error.message.includes("not supported")) {
            userMessage = "지원되지 않는 기능입니다.";
        } else if (error.message.includes("음성 생성 거부")) {
             userMessage = error.message; 
        }
    }

    throw new Error(userMessage);
  }
};
